//		Exec(ctx)
func (u *SubmitterUpsertBulk) Ignore() *SubmitterUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithIgnore())
	return u
}

// DoNothing configures the conflict_action to `DO NOTHING`.
// Supported only by SQLite and PostgreSQL.
func (u *SubmitterUpsertBulk) DoNothing() *SubmitterUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.DoNothing())
	return u
}

// Update allows overriding fields `UPDATE` values. See the SubmitterCreateBulk.OnConflict
// documentation for more info.
func (u *SubmitterUpsertBulk) Update(set func(*SubmitterUpsert)) *SubmitterUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&SubmitterUpsert{UpdateSet: update})
	}))
	return u
}

